8367 bool VPRecipeBuilder::shouldWiden(Instruction *I, VFRange &Range) const {
8368   assert(!isa<BranchInst>(I) && !isa<PHINode>(I) && !isa<LoadInst>(I) &&
8369          !isa<StoreInst>(I) && "Instruction should have been handled earlier");
8370   // Instruction should be widened, unless it is scalar after vectorization,
8371   // scalarization is profitable or it is predicated.
8372   auto WillScalarize = [this, I](ElementCount VF) -> bool {
8373     return CM.isScalarAfterVectorization(I, VF) ||
8374            CM.isProfitableToScalarize(I, VF) ||
8375            CM.isScalarWithPredication(I, VF);
8376   };
8377   return !LoopVectorizationPlanner::getDecisionAndClampRange(WillScalarize,
8378                                                              Range);
