8381 VPWidenRecipe *VPRecipeBuilder::tryToWiden(Instruction *I,
8382                                            ArrayRef<VPValue *> Operands,
8383                                            VPBasicBlock *VPBB) {
8384   switch (I->getOpcode()) {
8385   default:
8386     return nullptr;
8387   case Instruction::SDiv:
8388   case Instruction::UDiv:
8389   case Instruction::SRem:
8390   case Instruction::URem: {
8391     // If not provably safe, use a select to form a safe divisor before widening the
8392     // div/rem operation itself.  Otherwise fall through to general handling below.
8393     if (CM.isPredicatedInst(I)) {
8394       SmallVector<VPValue *> Ops(Operands);
8395       VPValue *Mask = getBlockInMask(I->getParent());
8396       VPValue *One =
8397           Plan.getOrAddLiveIn(ConstantInt::get(I->getType(), 1u, false));
8398       auto *SafeRHS = Builder.createSelect(Mask, Ops[1], One, I->getDebugLoc());
8399       Ops[1] = SafeRHS;
8400       return new VPWidenRecipe(*I, make_range(Ops.begin(), Ops.end()));
8401     }
8402     [[fallthrough]];
8403   }
8404   case Instruction::Add:
8405   case Instruction::And:
8406   case Instruction::AShr:
8407   case Instruction::FAdd:
8408   case Instruction::FCmp:
8409   case Instruction::FDiv:
8410   case Instruction::FMul:
8411   case Instruction::FNeg:
8412   case Instruction::FRem:
8413   case Instruction::FSub:
8414   case Instruction::ICmp:
8415   case Instruction::LShr:
8416   case Instruction::Mul:
8417   case Instruction::Or:
8418   case Instruction::Select:
8419   case Instruction::Shl:
8420   case Instruction::Sub:
8421   case Instruction::Xor:
8422   case Instruction::Freeze:
8423     SmallVector<VPValue *> NewOps(Operands);
8424     if (Instruction::isBinaryOp(I->getOpcode())) {
8425       // The legacy cost model uses SCEV to check if some of the operands are
8426       // constants. To match the legacy cost model's behavior, use SCEV to try
8427       // to replace operands with constants.
8428       ScalarEvolution &SE = *PSE.getSE();
8429       auto GetConstantViaSCEV = [this, &SE](VPValue *Op) {
8430         Value *V = Op->getUnderlyingValue();
8431         if (isa<Constant>(V) || !SE.isSCEVable(V->getType()))
8432           return Op;
8433         auto *C = dyn_cast<SCEVConstant>(SE.getSCEV(V));
8434         if (!C)
8435           return Op;
8436         return Plan.getOrAddLiveIn(C->getValue());
8437       };
8438       // For Mul, the legacy cost model checks both operands.
8439       if (I->getOpcode() == Instruction::Mul)
8440         NewOps[0] = GetConstantViaSCEV(NewOps[0]);
8441       // For other binops, the legacy cost model only checks the second operand.
8442       NewOps[1] = GetConstantViaSCEV(NewOps[1]);
8443     }
8444     return new VPWidenRecipe(*I, make_range(NewOps.begin(), NewOps.end()));
8445   };
8446 }
