8482 VPReplicateRecipe *VPRecipeBuilder::handleReplication(Instruction *I,
8483                                                       VFRange &Range) {
8484   bool IsUniform = LoopVectorizationPlanner::getDecisionAndClampRange(
8485       [&](ElementCount VF) { return CM.isUniformAfterVectorization(I, VF); },
8486       Range);
8487 
8488   bool IsPredicated = CM.isPredicatedInst(I);
8489 
8490   // Even if the instruction is not marked as uniform, there are certain
8491   // intrinsic calls that can be effectively treated as such, so we check for
8492   // them here. Conservatively, we only do this for scalable vectors, since
8493   // for fixed-width VFs we can always fall back on full scalarization.
8494   if (!IsUniform && Range.Start.isScalable() && isa<IntrinsicInst>(I)) {
8495     switch (cast<IntrinsicInst>(I)->getIntrinsicID()) {
8496     case Intrinsic::assume:
8497     case Intrinsic::lifetime_start:
8498     case Intrinsic::lifetime_end:
8499       // For scalable vectors if one of the operands is variant then we still
8500       // want to mark as uniform, which will generate one instruction for just
8501       // the first lane of the vector. We can't scalarize the call in the same
8502       // way as for fixed-width vectors because we don't know how many lanes
8503       // there are.
8504       //
8505       // The reasons for doing it this way for scalable vectors are:
8506       //   1. For the assume intrinsic generating the instruction for the first
8507       //      lane is still be better than not generating any at all. For
8508       //      example, the input may be a splat across all lanes.
8509       //   2. For the lifetime start/end intrinsics the pointer operand only
8510       //      does anything useful when the input comes from a stack object,
8511       //      which suggests it should always be uniform. For non-stack objects
8512       //      the effect is to poison the object, which still allows us to
8513       //      remove the call.
8514       IsUniform = true;
8515       break;
8516     default:
8517       break;
8518     }
8519   }
8520   VPValue *BlockInMask = nullptr;
8521   if (!IsPredicated) {
8522     // Finalize the recipe for Instr, first if it is not predicated.
8523     LLVM_DEBUG(dbgs() << "LV: Scalarizing:" << *I << "\n");
8524   } else {
8525     LLVM_DEBUG(dbgs() << "LV: Scalarizing and predicating:" << *I << "\n");
8526     // Instructions marked for predication are replicated and a mask operand is
8527     // added initially. Masked replicate recipes will later be placed under an
8528     // if-then construct to prevent side-effects. Generate recipes to compute
8529     // the block mask for this region.
8530     BlockInMask = getBlockInMask(I->getParent());
8531   }
